// Microsoft Graph faz validação inicial enviando ?validationToken=XYZ.
// Devemos ecoar o token em texto puro com 200 OK.
const query = $input.first().json.query ?? {};
if (query.validationToken) {
  return [{ json: { __responseMode: 'validation', token: query.validationToken } }];
}

// Notificação real: vem em body.value: [{ subscriptionId, clientState, resource, resourceData, ... }]
const body = $input.first().json.body ?? {};
const notifications = body.value ?? [];
if (!notifications.length) throw new Error('No notifications in body');

const expectedClientState = $env['MICROSOFT_PUSH_NOTIFICATION_TOKEN'];
return notifications.map(n => {
  if (n.clientState !== expectedClientState) throw new Error('Invalid Microsoft clientState');
  return { json: n };
});

// Classifica eventos: new / modified / cancelled
// Microsoft Graph delta retorna eventos com '@removed' pra deletados.
const items = $json.value ?? [];
const memberId = $('Find Member by Subscription ID').first().json[0].member_id;
return items.map(e => {
  const isCancelled = !!e['@removed'] || e.isCancelled === true;
  const isNew = !e['@removed'] && (!e.lastModifiedDateTime || e.createdDateTime === e.lastModifiedDateTime);
  return {
    json: {
      externalEventId: e.id,
      externalProvider: 'microsoft',
      memberId,
      eventType: isCancelled ? 'cancelled' : (isNew ? 'new' : 'modified'),
      title: e.subject ?? '(sem título)',
      description: e.bodyPreview ?? null,
      location: e.location?.displayName ?? null,
      startAt: e.start?.dateTime ? `${e.start.dateTime}Z` : null,
      endAt: e.end?.dateTime ? `${e.end.dateTime}Z` : null,
      allDay: e.isAllDay ?? false
    }
  };
});
